import{_ as o,c as t,o as l,Q as e}from"./chunks/framework.42e95ed4.js";const _=JSON.parse('{"title":"命令行快捷键","description":"","frontmatter":{"title":"命令行快捷键","date":"2019-09-10T21:31:23.000Z","tags":["命令行"],"next":{"text":"环境搭建 - 命令行插件","link":"/post/cli-plugin"},"prev":{"text":"参数处理 & 解构赋值","link":"/post/deconstruction"}},"headers":[],"relativePath":"post/cli-hot-key.md","filePath":"post/cli-hot-key.md","lastUpdated":null}'),r={name:"post/cli-hot-key.md"},i=e('<h1 id="命令行快捷键" tabindex="-1">命令行快捷键 <a class="header-anchor" href="#命令行快捷键" aria-label="Permalink to &quot;命令行快捷键&quot;">​</a></h1><h2 id="常用" tabindex="-1">常用 <a class="header-anchor" href="#常用" aria-label="Permalink to &quot;常用&quot;">​</a></h2><ul><li><strong><code>Ctrl L</code></strong>：清屏</li><li><strong><code>Ctrl M</code></strong>：等效于回车</li><li><strong><code>Ctrl C</code></strong>：中断正在当前正在执行的程序</li></ul><h2 id="历史命令" tabindex="-1">历史命令 <a class="header-anchor" href="#历史命令" aria-label="Permalink to &quot;历史命令&quot;">​</a></h2><ul><li><strong><code>Ctrl P</code></strong>：上一条命令，可以一直按表示一直往前翻</li><li><strong><code>Ctrl N</code></strong>：下一条命令</li><li><strong><code>Ctrl R</code></strong>：再按历史命令中出现过的字符串：按字符串寻找历史命令（重度推荐）</li></ul><h2 id="命令行编辑" tabindex="-1">命令行编辑 <a class="header-anchor" href="#命令行编辑" aria-label="Permalink to &quot;命令行编辑&quot;">​</a></h2><ul><li><strong><code>Tab</code></strong>：自动补齐（重度推荐）</li><li><strong><code>Ctrl A</code></strong>：移动光标到命令行首</li><li><strong><code>Ctrl E</code></strong>：移动光标到命令行尾</li><li><strong><code>Ctrl B</code></strong>：光标后退</li><li><strong><code>Ctrl F</code></strong>：光标前进</li><li><strong><code>Alt F</code></strong>：光标前进一个单词</li><li><strong><code>Alt B</code></strong>：光标后退一格单词</li><li><strong><code>Ctrl ]</code></strong>：从当前光标往后搜索字符串，用于快速移动到该字符串</li><li><strong><code>Ctrl Alt ]</code></strong>：从当前光标往前搜索字符串，用于快速移动到该字符串</li><li><strong><code>Ctrl H</code></strong>：删除光标的前一个字符</li><li><strong><code>Ctrl D</code></strong>：删除当前光标所在字符</li><li><strong><code>Ctrl K</code></strong>：删除光标之后所有字符</li><li><strong><code>Ctrl U</code></strong>：清空当前键入的命令</li><li><strong><code>Ctrl W</code></strong>：删除光标前的单词(Word, 不包含空格的字符串)</li><li><strong><code>Ctrl \\</code></strong>：删除光标前的所有空白字符</li><li><strong><code>Ctrl Y</code></strong>：粘贴 <strong><code>Ctrl W</code></strong> 或 <strong><code>Ctrl K</code></strong> 删除的内容</li><li><strong><code>Alt .</code></strong>：粘贴上一条命令的最后一个参数（很有用）</li><li><strong><code>Alt [0-9] Alt .</code></strong>：粘贴上一条命令的第 <code>[0-9]</code> 个参数</li><li><strong><code>Alt [0-9] Alt . Alt.</code></strong>：粘贴上上一条命令的第 <code>[0-9]</code> 个参数</li><li><strong><code>Ctrl X Ctrl E</code></strong>：调出系统默认编辑器编辑当前输入的命令，退出编辑器时，命令执行</li></ul><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><ul><li><strong><code>Ctrl Z</code></strong>：把当前进程放到后台（之后可用&#39;&#39;fg&#39;&#39;命令回到前台）</li><li><strong><code>Shift Insert</code></strong>：粘贴（相当于 Windows 的 <strong><code>Ctrl V</code></strong>）</li><li>在命令行窗口选中即复制</li><li>在命令行窗口中键即粘贴，也可用 <strong><code>Shift Insert</code></strong> 代替</li><li><strong><code>Ctrl PageUp</code></strong>：屏幕输出向上翻页</li><li><strong><code>Ctrl PageDown</code></strong>：屏幕输出向下翻页</li><li><strong><code>Alt D</code></strong>：删除当前单词</li><li><strong><code>Ctrl + ?</code></strong>：撤消前一次输入</li></ul><h2>文档信息</h2><blockquote><ul><li>文章来源：<a href="https://gist.github.com/zhulianhua/befb8f61db8c72b4763d" target="_blank" rel="noreferrer">https://gist.github.com/zhulianhua/befb8f61db8c72b4763d</a></li></ul></blockquote>',11),n=[i];function c(s,d,a,g,h,u){return l(),t("div",null,n)}const b=o(r,[["render",c]]);export{_ as __pageData,b as default};
